import{pipe,drop,every}from"@hyperjump/pact";import*as Instance from"../lib/instance.js";import*as Schema from"../lib/schema.js";import Validation from"../lib/keywords/validation.js";import{getKeywordName}from"../lib/keywords.js";const id="https://json-schema.org/keyword/draft-04/additionalItems",compile=async(e,t,r)=>{var a=getKeywordName(e.dialectId,"https://json-schema.org/keyword/draft-04/items"),a=await Schema.step(a,r);return[Schema.typeOf(a,"array")?Schema.length(a):Number.MAX_SAFE_INTEGER,await Validation.compile(e,t)]},interpret=([e,t],r,a,i,o)=>!Instance.typeOf(r,"array")||pipe(Instance.iter(r),drop(e),every(e=>Validation.interpret(t,e,a,i,o))),collectEvaluatedItems=(t,r,e,a)=>{if(!interpret(t,r,e,a))return!1;const i=new Set;for(let e=t[0];e<Instance.length(r);e++)i.add(e);return i};export default{id:id,compile:compile,interpret:interpret,collectEvaluatedItems:collectEvaluatedItems};